INSERT INTO `messages` VALUES (1,1,2,'halo',1,'2026-05-11 17:00:27'),(2,1,2,'вүЎЖ’ГңВҝ SIAGA BENCANA О“ГҮГ¶ AgriMapGIS\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nвүЎЖ’ГҙГ¬ Lokasi   : Sawah Blok C - Terkena Banjir\nвүЎЖ’ГІГү Waktu    : 11/05/2026 17:28\nО“ГңГЎвҲ©в••Г…  Kejadian : Terjadi banjir akibat luapan sungai setelah hujan deras 3 jam. Tanaman padi usia 90 hari terendam 50cm.\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nвүЎЖ’ГҙГҜ TINDAKAN SEGERA:\n1. Segera lakukan drainase dan pompaan air\n2. Proteksi tanaman dengan fungisida pasca banjir\n3. Berikan pupuk daun untuk pemulihan tanaman\n4. Dokumentasikan kerusakan untuk klaim asuransi\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nPesan otomatis dari sistem AgriMapGIS oleh Petugas PPL Rajabasa. Hubungi PPL untuk bantuan teknis lebih lanjut.',1,'2026-05-11 17:28:37'),(3,1,3,'вүЎЖ’ГңВҝ SIAGA BENCANA О“ГҮГ¶ AgriMapGIS\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nвүЎЖ’ГҙГ¬ Lokasi   : Sawah Blok C - Terkena Banjir\nвүЎЖ’ГІГү Waktu    : 11/05/2026 17:28\nО“ГңГЎвҲ©в••Г…  Kejadian : Terjadi banjir akibat luapan sungai setelah hujan deras 3 jam. Tanaman padi usia 90 hari terendam 50cm.\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nвүЎЖ’ГҙГҜ TINDAKAN SEGERA:\n1. Segera lakukan drainase dan pompaan air\n2. Proteksi tanaman dengan fungisida pasca banjir\n3. Berikan pupuk daun untuk pemulihan tanaman\n4. Dokumentasikan kerusakan untuk klaim asuransi\nО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶ГјО“Г¶Гј\nPesan otomatis dari sistem AgriMapGIS oleh Petugas PPL Rajabasa. Hubungi 